package core_java;

public class DataType {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		byte temperature=45;
		System.out.println(temperature);
		
		//5 digits are used 
		short distance=12488;
		System.out.println(distance);
		
		//10 digits are used
		int i=1356768909;
		System.out.println(i);
		
		// after decimal number 6 digit are to be used
		float weight=65.11111137889f;
		System.out.println(weight);
		
		//are used 10 digit only
		
		long punepopulation=1200000000l;
		System.out.println(punepopulation);
			
		// after the decimal number 14/13 digits are to be used in double data type
		//last f is not a compalsary
			
        double d=65.1223345778899843f;
		System.out.println(d);
		
		//logical value to be used like (true or false)
		boolean b=false;
		System.out.println(b);
		
		//char data type only used character like a,b,c,d etc do not used any name,sentence,passage
		char ch='s';
		System.out.println(ch);
		
		//string first letter are capital letter and string are used multiple character
		//there are used in " "
		String s="shradha";
		System.out.println(s);
		
		

	}

}
